var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"저기…….","JPN":"あのさ……","ENG":"Hey...","TWN":"那個……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"왜 아까부터 여기 가만히 있는 거야? 혹시 길을 잃은 건 아니지?","JPN":"なんでさっきからここで止まってるの？　もしかして道に迷った？","ENG":"Why are you just standing here? You aren’t lost, are you?","TWN":"為什麼從剛才就一直站在這裡？你應該不是迷路吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"뭐야. 뜸들이길래 엄청 대단한 말이라도 하려나 했더니……","JPN":"なによ。もったいぶるからなんかすごいことでも言うのかと思ったら……","ENG":"Oh. I thought you were going to say something important after all that hesitating...","TWN":"什麼嘛，在那邊吞吞吐吐的，我還以為你會有什麼驚人的發言……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"걱정하지 말고 얌전히 따라오기나 해. 의뢰인과는 이 근처에서 만나기로 했으니까.","JPN":"心配しないでおとなしくついてきて。依頼人とはこの辺りで会う予定だから。","ENG":"Don’t worry and just follow me quietly. I agreed to meet my contact around here.","TWN":"安啦，你乖乖跟著我就好，我和委託人約在這附近見面。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"이 근처? 하수도에서 말이야?","JPN":"この辺り？　下水道で？","ENG":"Around here? You mean inside the sewers?","TWN":"這附近？下水道裡？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"그, 그래! 내 말은 노예라 못 믿겠다는 거야?","JPN":"そ、そうよ！　奴隷の言うことは信じられない？","ENG":"T-that’s right! You can’t trust me since I’m a slave, is that it?","TWN":"對…對啊！因為我是奴隸你就懷疑我嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그런 뜻이 아니라…….","JPN":"そういう意味じゃなくて……","ENG":"No, that's not what I meant...","TWN":"我不是這個意思……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_WOMAN","text":{"KOREA":"시간을 제대로 지켰군요, 루크레시아.","JPN":"約束の時間どおりですね、ルクレシア。","ENG":"You’re on time, Lucrecia.","TWN":"很準時嘛，露可蕾西亞。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_WOMAN","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"저 기사들은…… 설마 여기까지 쫓아온 거야?","JPN":"あの騎士は……もしかしてここまで追って？","ENG":"Those knights... Don’t tell me that they followed us all the way here?!","TWN":"那些騎士……追到這裡來了嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"가만히 있어, 겁쟁아. 방위 기사단이 아니라 서쪽 신전에서 온 사람들이야.","JPN":"じっとしてて、弱虫。防衛騎士団じゃなくて、西方の神殿から来た人たちよ。","ENG":"Stay still, coward. Those aren’t Defense Knights. They’re from the Western Temple.","TWN":"你安靜啦，膽小鬼。他們不是護衛騎士團的人，他們是從西方神殿來的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"약속한 대로 <color=#ffd34c>부활의 지팡이</color>를 가져왔어요, 사제님.","JPN":"約束どおり、<color=#ffd34c>復活の杖</color>を持ってきました、司祭様。","ENG":"I have brought the <color=#ffd34c>Staff of Resurrection</color> as promised, Your Grace.","TWN":"這是你要的<color=#ffd34c>復活之杖</color>，祭司大人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"대신전에서 직접 보셨을 테니까, 진품인지 아닌지는 감별할 필요 없겠죠?","JPN":"大神殿で直接見たはずですから、本物かどうか鑑定する必要はないでしょう？","ENG":"Since you have probably seen this in person at the Great Temple, there should be no need to confirm its authenticity, right?","TWN":"你應該有在大神殿中親眼見過，就不需要再鑑識真偽了吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"그래요. 확실히 그 찬란한 빛은 200년만에 다시 나타난 성녀의 징표…….","JPN":"そうですね。この眩い光は確かに200年ぶりに再び現れた聖女の証……","ENG":"That is true. Surely that radiant light is the sign of the Saintess who has reappeared after 200 years...","TWN":"嗯嗯，那耀眼的光芒，確實是睽違200年再次出現的聖女信物……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"진품이 틀림없군요. 아주 훌륭해요.","JPN":"本物で間違いありません。とても素晴らしい。","ENG":"There is no doubt that it is the real artifact. You did a great job.","TWN":"沒錯，你做得非常好。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"부활의 지팡이라면……. 성녀에게 주어진다는 성물 아니야?","JPN":"復活の杖って……　聖女に与えられるっていう聖物じゃなかった？","ENG":"The Staff of Resurrection... Isn’t that the Holy Relic bestowed upon the Saintess?","TWN":"復活之杖……不是賦予聖女的聖物嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"맞아. 성녀의 상징이자 구원자를 공인할 수 있는 권리도 주어지지.","JPN":"そうよ。聖女の証であり、救世主を公認できる権利も得られるの。","ENG":"That’s right. It’s a symbol of the Saintess and grants the authority to officially recognize the Savior.","TWN":"沒錯， 它不只是聖女的象徵，也有承認救贖者的權利。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그런 물건을 어떻게…….","JPN":"そんなものをどうやって……","ENG":"How did you get your hands on something like that...?","TWN":"你為什麼要……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"가축이 도둑질을 할 거라고 누가 생각하겠어? 다른 데도 아니고 대신전에서.","JPN":"家畜が盗みをはたらくだなんて誰も考えられないでしょう？　他のどこでもなく、大神殿で。","ENG":"Who would have thought that cattle would commit robbery? Even more so in the Great Temple of all places.","TWN":"誰想得到畜生會偷東西？而且還是在大神殿裡？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"신전에서 기른 노예 출신이라 그런지 제법 잘 알고 있군요.","JPN":"神殿で育った奴隷出身だからか、かなり詳しいですね。","ENG":"It seems that you are well versed in such things as you were raised as a slave in the temple.","TWN":"因為你是神殿裡的奴隸嗎？你知道的還不少呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"자, 루크레시아. 그러면 이제 그 지팡이를 저에게 주세요.","JPN":"さあ、ルクレシア。それではその杖を渡してください。","ENG":"Now then, Lucrecia. Please hand me the staff.","TWN":"來吧，露可蕾西亞，把那個杖交給我吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"아니. 그렇게는 못하겠어요.","JPN":"いいえ。そうはできませんね。","ENG":"No, I can’t do that.","TWN":"不行，還不能交給你。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"……다시 말해 보시겠어요?","JPN":"……どういうことですか？","ENG":"...What did you say just now?","TWN":"……我有聽錯嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"지팡이를 제대로 가져 왔으니까, 사제님도 성의를 보여 주셔야죠.","JPN":"杖は確かに持ってきたのですから、司祭様も誠意を見せてくださらないと。","ENG":"I brought the staff as promised. Now, it’s your turn to keep your part of the deal.","TWN":"杖我帶來了，那您也要展現您的誠意吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"지금 이 자리에서 제 노예 증서를 불태워 주세요.","JPN":"今、この場で私の奴隷証書を燃やしてください。","ENG":"Burn my slave certificate right now.","TWN":"現在就當場燒掉我的奴隸證。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":"노예 주제에 감히! 이 분이 누구신지 알고도 그러느냐!","JPN":"奴隷の分際で！　この方がどなたと心得る！","ENG":"How dare a lowly slave like you! Do you know who she is?!","TWN":"大膽奴隸！你知道你在跟誰對話嗎！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"서쪽 신전의 성녀 후보시죠.","JPN":"西方の神殿の聖女候補でしょう？","ENG":"She is the candidate for the Sainthood from the Western Temple.","TWN":"西方神殿的聖女候選人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"그래서 다른 후보들보다 먼저 지팡이를 가지고 싶으신 거고요.","JPN":"だから他の候補よりも先に杖を手に入れたいわけで。","ENG":"That’s why she wants to get her hands on the staff before the other candidates.","TWN":"所以才想要比其他候選人先拿到杖吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"아마도 제게 훔쳐오라고 시킨 지팡이가 스스로 주인을 찾아왔다는 식의 기적으로 포장하려는 셈 아닌가요?","JPN":"多分私に盗んでこいと指示した杖が、自ら主人を探して来たという奇跡に偽装するつもりじゃないんですか？","ENG":"I’m guessing she wants to claim that the stolen staff had returned to its rightful owner, thus performing a miracle.","TWN":"你是打算對外宣稱，這把你要我偷來的杖，是自己找到主人的，這是一個神蹟對吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":"감히……! 신전의 이름을 욕보이고도 구원을 받을 것 같으냐!","JPN":"この……！　神殿を侮辱しておいて救いを受けられるとでも思ってるのか！","ENG":"How dare you...! Do you think you will still receive salvation after insulting the temple like this?!","TWN":"放肆……！你這樣侮辱神殿之名，還奢望得到救贖嗎！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"……전 그런 거 안 믿어요. 신전에서 하는 짓을 보면 그냥 잘 먹고 잘 사는 게 제일 같거든요.","JPN":"……私はそんなの信じてません。神殿のやり方を見てると、ただよく食べてよく暮らすのが一番だと思いますから。","ENG":"...I don’t believe in such things. Based on what I’ve seen in the temple, eating well and having a roof over my head seems to be the best lifestyle.","TWN":"……我不信那套，就我平時在神殿的觀察，在神殿裡吃得好睡得好是最重要的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":"저 년이……! 비실거리는 꼬마 하나 데려왔다고 간이 부어선!","JPN":"小娘が……！　今にも倒れそうなガキを一人連れてきたからって調子に乗りおって！","ENG":"Why you little brat...! Don’t get cocky just because you brought some skinny kid with you!","TWN":"死丫頭……！以為帶個瘦弱的小鬼來給你撐腰，就可以那麼目中無人嗎！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"기다리세요.","JPN":"待ちなさい。","ENG":"Please stand down.","TWN":"你等一下。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"자, 제가 사들인 당신의 노예 증서입니다. 루크레시아.","JPN":"さあ、私が買い入れたあなたの奴隷証書です。ルクレシア。","ENG":"See here. This is your slave certificate which I have bought, Lucrecia.","TWN":"這是你的奴隸證，露可蕾西亞。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"의심이 간다면 확인해 보세요.","JPN":"疑わしいのなら確認してみてください。","ENG":"If you don’t believe me, take a look for yourself.","TWN":"懷疑的話可以檢查看看。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"……네. 틀림없어요.","JPN":"……はい。間違いないです。","ENG":"...Yes, there’s no doubt about it.","TWN":"……是我的奴隸證沒錯。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"신전에 노예는 많습니다. 지키기 어려운 약속도 아니죠.","JPN":"神殿に奴隷はたくさんいます。守れない約束でもありません。","ENG":"The temple has many slaves. This is not a difficult promise to keep.","TWN":"神殿裡有那麼多奴隸，這有什麼難的呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"약속을 지켰으니 이제 지팡이를 넘겨 주시겠어요?","JPN":"約束は果たしましたから、もう杖を渡してもらえますか？","ENG":"Now that I have kept my end of the bargain, will you please hand me the staff?","TWN":"我已經照約定燒掉奴隸證，可以把杖給我了嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"여기 있어요. 마음대로 가져가세요.","JPN":"どうぞ。勝手に持っていってください。","ENG":"Here. Do what you want with it.","TWN":"給你，拿去吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"고마워요. 그동안 수고가 많았습니다, 루크레시아.","JPN":"ありがとうございます。ご苦労さまでした、ルクレシア。","ENG":"Thank you. You did a great job, Lucrecia.","TWN":"謝謝，辛苦了，露可蕾西亞。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"……추가로 저 남자애가 방위 기사단에 쫓길 때 저를 도와 줬어요.","JPN":"……それから防衛騎士団に追われてるときに、あの男の子が助けてくれたんです。","ENG":"...Also, that boy helped me escape from the Defense Knights.","TWN":"……對了，護衛騎士團追捕我的時候，他也有幫我。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"고마우시다면 저 녀석에게 은전 몇 푼이라도 던져 주세요.","JPN":"ありがたいというなら、あいつに銀貨をいくらかあげてください。","ENG":"If you’re feeling grateful to me, please toss him a few coins.","TWN":"要謝的話，就賞他點銀子吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"흐음…… 그랬군요. 이 역시 저에게 성녀가 되라는 신의 뜻이겠죠.","JPN":"ふん……そうでしたか。これも私に聖女になれという神意でしょう。","ENG":"Hmm... I see. This must also be a sign from God that I should become the Saintess.","TWN":"嗯嗯……有這種事，看來我註定要成為聖女呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"보아하니 용병인 모양인데, 소년은 이름이 뭐죠?","JPN":"見たところ傭兵のようですが、少年のお名前は？","ENG":"Judging by your looks, you seem to be a mercenary. What is your name?","TWN":"你看起來好像是傭兵，你叫什麼名字？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"레이…… 라고 합니다. 사제님.","JPN":"レイ……です。司祭様。","ENG":"My name... is Ray, Your Grace.","TWN":"我叫……雷伊，祭司大人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"레이. 레이라……","JPN":"レイ。レイ……","ENG":"Ray? Ray...","TWN":"雷伊，雷伊……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"기억해 두겠어요.","JPN":"覚えておきます。","ENG":"I will not forget.","TWN":"我記住了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"제가 성녀가 될 수 있도록 도운 두 시체의 이름을 말이죠.","JPN":"私が聖女になるように手伝ってくれた遺体たちの名前をね。","ENG":"The names of the two corpses that helped me become the Saintess, I mean.","TWN":"我記住是哪兩具屍體幫助我成為聖女的了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?!","TWN":"什麼……？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"루크레시아, 우리 포위당했어.","JPN":"ルクレシア、僕たち囲まれてるよ。","ENG":"Lucrecia, we’ve been surrounded.","TWN":"露可蕾西亞，我們被包圍了。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"……이게 무슨 짓이야?","JPN":"……どういうこと？","ENG":"...What’s the meaning of this?!","TWN":"……你這是什麼意思？！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"노예의 인적 기록은 노예 증서로만 관리되죠.","JPN":"奴隷の記録は奴隷証書のみで管理されます。","ENG":"A slave's personal record is maintained only through their slave certificate.","TWN":"奴隸個人的相關紀錄是透過奴隸證來管理的，"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"자유를 대가로, 당신은 그냥 이 세상에 존재하지 않는 인간이 된 거예요.","JPN":"自由を得た代わりに、あなたはもうこの世に存在しない人間になったのです。","ENG":"As the price for your freedom, you have become a person that no longer exists in this world.","TWN":"自由的代價，就是你不再存在於這個世界上。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그러니까…… 날 죽여서 입을 막으시겠다?","JPN":"だから……私を殺して口封じをするってこと？","ENG":"So... You’re going to kill me to keep my mouth shut?","TWN":"意思是……你要把我滅口？"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"그 말이 맞아요. 지팡이는 스스로 주인을 찾아 온 거죠.","JPN":"そのとおりです。杖は自ら主人の元へ来ました。","ENG":"That is correct. The staff has returned to its rightful owner by itself.","TWN":"你說的沒錯，這把杖是自己找到主人的，"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"더러운 노예 계집이 훔쳐 온 게 아니라.","JPN":"汚い奴隷が盗んできたのではなくてね。","ENG":"Not through an act of robbery by some filthy slave.","TWN":"才不是什麼骯髒的奴隸偷來的。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"역시…… 이럴 줄 알았어……. 약속 따위 지킬 리 없는데……!","JPN":"やっぱり……こうなると思ったわ……　約束なんて守るわけないのに……！","ENG":"I knew it... I knew this would happen... There’s no way you would keep your promise...!","TWN":"我就知道……會這樣……你怎麼可能遵守約定……！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"하지만…… 약속을 믿고 지팡이를 훔쳐 온 거 아니었어?","JPN":"でも……約束を信じて杖を盗んできたんじゃないの？","ENG":"But... Didn’t you steal the staff because you believed that she would keep her promise?","TWN":"可是……你不是相信她才把杖偷來的嗎？"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"시끄러워!! 네가 뭘 안다고 그래!","JPN":"うるさい！！　あんたに何がわかるの！","ENG":"Shut up!! What the hell do you know?!","TWN":"閉嘴！！你懂什麼！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"노예 증서가 사라졌으니 내 목적은 달성했어! 이제 도망치기만 하면 끝이야!","JPN":"奴隷証書がなくなって私の目的は達成されたわ！　あとは逃げるだけよ！","ENG":"Since my slave certificate is gone, I achieved my goal! I just need to escape!","TWN":"我的目的就是要奴隸證消失！現在只要逃出去我就自由了！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"쉽게 벗어날 수 있을지는 모르겠지만 말이죠.","JPN":"簡単に逃げられるかはわかりませんけどね。","ENG":"That’s \\"if\\" you are able to escape.","TWN":"前提是逃得出去的話。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"믿음을 지키기 위해 검을 든 자들이여.","JPN":"信心を守るため剣を持った者たちよ。","ENG":"The righteous who have taken up the sword to protect our faith.","TWN":"忠心的騎士們，"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"저 둘을 우리 신앙의 거름으로 만드세요.","JPN":"あの二人を私たちの信仰の肥やしにしてあげなさい。","ENG":"Let those two become one with the foundation of our faith.","TWN":"讓那兩個孩子成為我們信仰的養分吧。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};